function showToast(message) {
  var toast = document.querySelector(".toast");
  if (!toast) return;
  toast.textContent = message;
  toast.classList.add("show");
  window.clearTimeout(showToast.timer);
  showToast.timer = window.setTimeout(function () {
    toast.classList.remove("show");
  }, 1800);
}

function wireHome() {
  var range = document.querySelector("#angerRange");
  var bubble = document.querySelector("#angerBubble");
  var face = document.querySelector("#faceMood");
  if (!range || !bubble || !face) return;
  function paint() {
    var value = Number(range.value);
    bubble.textContent = value;
    bubble.style.bottom = (44 + value * 2.25) + "px";
    face.dataset.level = value > 70 ? "hot" : value > 38 ? "mid" : "low";
    face.querySelector("b").textContent = value > 70 ? "需要暂停" : value > 38 ? "有点上头" : "现在很稳";
  }
  range.addEventListener("input", paint);
  paint();
  document.querySelectorAll(".person").forEach(function (button) {
    button.addEventListener("click", function () {
      document.querySelectorAll(".person").forEach(function (item) { item.classList.remove("active"); });
      button.classList.add("active");
      showToast("已切换到" + button.dataset.name);
    });
  });
}

function wireRecord() {
  var chips = document.querySelectorAll(".mood-chip, .tag-chip");
  chips.forEach(function (chip) {
    chip.addEventListener("click", function () {
      var group = chip.dataset.group;
      document.querySelectorAll('[data-group="' + group + '"]').forEach(function (item) {
        item.classList.remove("selected");
      });
      chip.classList.add("selected");
    });
  });
  var note = document.querySelector("#recordNote");
  var count = document.querySelector("#noteCount");
  if (note && count) {
    note.addEventListener("input", function () { count.textContent = note.value.length + "/120"; });
  }
  var save = document.querySelector("#saveRecord");
  if (save) {
    save.addEventListener("click", function () {
      if (!note.value.trim()) {
        showToast("先写一句发生了什么");
        note.focus();
        return;
      }
      showToast("已记一笔，今晚再复盘");
    });
  }
}

function wireStats() {
  document.querySelectorAll(".range-tab").forEach(function (tab) {
    tab.addEventListener("click", function () {
      document.querySelectorAll(".range-tab").forEach(function (item) { item.classList.remove("active"); });
      tab.classList.add("active");
      document.querySelector("#trendHint").textContent = tab.dataset.hint;
    });
  });
}

function wireProfile() {
  document.querySelectorAll("[data-action]").forEach(function (button) {
    button.addEventListener("click", function () {
      showToast(button.dataset.action);
    });
  });
}

window.addEventListener("DOMContentLoaded", function () {
  wireHome();
  wireRecord();
  wireStats();
  wireProfile();
});

